define(["jquery","jqueryui"],function($){"use strict";function bindAutoUrl(action){var title=$("#title");var link=$("#link");var id=$("#id");title.on("focusout",function(){if(!title.val()||link.val()){return}$.ajax({method:"POST",url:M.cfg.wwwroot+"/local/kopere_dashboard/plugins/pages/ajax.php",data:{action:action,title:title.val(),id:id.val()},dataType:"text"}).done(function(data){link.val(data)}).fail(function(){if(window.console){window.console.warn(M.util.get_string("ajax_error","koperedashboard_pages"))}})})}return{pageUrl:function(){bindAutoUrl("pageurl")},menuUrl:function(){bindAutoUrl("menuurl")},view_page:function(){$(".jquery-ui-tabs").tabs();$(".jquery-ui-accordion").accordion({heightStyle:"content"})}}});